css:
.loader {
  color: var(--loader-color, #8b5cf6);
  --loader-secondary-color: #c4b5fd;
  --loader-bg: #ffffff;
width: 45px;
aspect-ratio: 1;
--c:no-repeat linear-gradient(currentColor 0 0);
background:
var(--c) 0 0,
var(--c) 0 100%,
var(--c) 50% 50%,  
 var(--c) 100% 0,
var(--c) 100% 100%;
animation: l13 1s infinite alternate;
}

@keyframes l13 {
0%,10% {background-size:20% 100%}
50% {background-size:20% 20%}
90%,100% {background-size:100% 20%}
}
